import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Introduzione a Fabric e al Modding","description":"Una breve introduzione a Fabric e al modding in Minecraft: Java Edition.","frontmatter":{"title":"Introduzione a Fabric e al Modding","description":"Una breve introduzione a Fabric e al modding in Minecraft: Java Edition.","authors":["IMB11","itsmiir"],"authors-nogithub":["basil4088"],"search":false,"files":[]},"headers":[],"relativePath":"it_it/1.20.4/develop/getting-started/introduction-to-fabric-and-modding.md","filePath":"versions/1.20.4/translated/it_it/develop/getting-started/introduction-to-fabric-and-modding.md","lastUpdated":1739538073000}`);var a={name:`it_it/1.20.4/develop/getting-started/introduction-to-fabric-and-modding.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Introduzione a Fabric e al Modding <a class="header-anchor" href="#h1" aria-label="Permalink to “Introduzione a Fabric e al Modding”">​</a></h1><h2 id="prerequisiti" tabindex="-1">Prerequisiti <a class="header-anchor" href="#prerequisiti" aria-label="Permalink to “Prerequisiti”">​</a></h2><p>Prima d&#39;iniziare, dovresti avere una comprensione basilare dello sviluppo con Java, e una comprensione della Programmazione Orientata agli Oggetti (OOP).</p><p>Se questi concetti non ti sono familiari, potresti voler cercare qualche tutorial su Java e sulla OOP prima di cominciare a fare modding, ecco alcune risorse (in inglese) che puoi usare per imparare Java e OOP:</p><ul><li><a href="https://www.w3schools.com/java/" target="_blank" rel="noreferrer">W3: Java Tutorials</a></li><li><a href="https://www.codecademy.com/learn/learn-java" target="_blank" rel="noreferrer">Codecademy: Learn Java</a></li><li><a href="https://www.w3schools.com/java/java_oop.asp" target="_blank" rel="noreferrer">W3: Java OOP</a></li><li><a href="https://medium.com/@Adekola_Olawale/beginners-guide-to-object-oriented-programming-a94601ea2fbd" target="_blank" rel="noreferrer">Medium: Introduction to OOP</a></li></ul><h3 id="terminologia" tabindex="-1">Terminologia <a class="header-anchor" href="#terminologia" aria-label="Permalink to “Terminologia”">​</a></h3><p>Prima di cominciare, chiariamo alcuni termini che incontrerai nel moddare con Fabric:</p><ul><li><strong>Mod</strong>: Una modifica al gioco, che aggiunge nuove funzionalità oppure ne modifica di esistenti.</li><li><strong>Loader di Mod</strong>: Uno strumento che carica le mod nel gioco, per esempio il Loader di Fabric.</li><li><strong>Mixin</strong>: Uno strumento per modificare il codice del gioco al runtime - vedi <a href="https://fabricmc.net/wiki/tutorial:mixin_introduction" target="_blank" rel="noreferrer">Mixin Introduction</a> per maggiori informazioni.</li><li><strong>Gradle</strong>: Uno strumento per l&#39;automatizzazione del build usato per costruire e compilare mod, usato da Fabric per costruire le mod.</li><li><strong>Mapping</strong>: Un insieme di mapping che mappano codice offuscato a codice leggibile.</li><li><strong>Offuscamento</strong>: Il processo di rendere il codice difficile da comprendere, usato da Mojang per proteggere il codice di Minecraft.</li><li><strong>Remapping</strong>: Il processo di rimappare codice offuscato a codice leggibile.</li></ul><h2 id="cos-e-fabric" tabindex="-1">Cos&#39;è Fabric? <a class="header-anchor" href="#cos-e-fabric" aria-label="Permalink to “Cos&#39;è Fabric?”">​</a></h2><p>Fabric è una toolchain di modding leggera per Minecraft: Java Edition.</p><p>È progettato per essere una piattaforma per modding semplice e facile da usare. Fabric è un progetto guidato dalla comunità, ed è open-source, per cui chiunque può contribuire al progetto.</p><p>Dovresti conoscere le quattro componenti principali di Fabric:</p><ul><li><strong>Loader di Fabric</strong>: Un loader di mod flessibile indipendente dalla piattaforma progettato per Minecraft e per altri giochi e applicazioni.</li><li><strong>Loom di Fabric</strong>: Un plugin Gradle che permette agli sviluppatori di sviluppare ed effettuare debug delle mod facilmente.</li><li><strong>API di Fabric</strong>: Un insieme di API e di strumenti per sviluppatori di mod da usare quando si creano mod.</li><li><strong>Yarn</strong>: Un insieme di mapping Minecraft aperti, gratuiti per tutti da usare sotto la licenza Creative Commons Zero.</li></ul><h2 id="perche-e-necessario-fabric-per-moddare-minecraft" tabindex="-1">Perché È Necessario Fabric per Moddare Minecraft? <a class="header-anchor" href="#perche-e-necessario-fabric-per-moddare-minecraft" aria-label="Permalink to “Perché È Necessario Fabric per Moddare Minecraft?”">​</a></h2><blockquote><p>Il modding è il processo di modifica del gioco per cambiarne il comportamento o per aggiungere nuove funzionalità - nel caso di Minecraft, questo può essere qualsiasi cosa dall&#39;aggiungere nuovi oggetti, blocchi, o entità, al cambiare le meccaniche del gioco o aggiungere nuove modalità di gioco.</p></blockquote><p>Minecraft: Java Edition è offuscato da Mojang, il che rende la pura modifica difficile. Tuttavia, aiutandosi con strumenti di modding come Fabric, il modding diventa molto più facile. Ci sono vari sistemi di mapping che possono aiutare in questo processo.</p><p>Loom rimappa il codice offuscato a un formato leggibile usando questi mapping, rendendo la comprensione e la modifica del codice del gioco più semplice per i modder. Yarn è una scelta popolare ed eccellente di mapping per questo, ma esistono anche altre opzioni. Ogni progetto di mapping potrebbe avere il suo punto forte o la sua focalizzazione.</p><p>Loom ti permette di sviluppare e compilare mod facilmente in riferimento a codice rimappato, e il Loader di Fabric ti permette di caricare queste mod nel gioco.</p><h2 id="cosa-fornisce-l-api-di-fabric-e-perche-e-necessaria" tabindex="-1">Cosa Fornisce l&#39;API di Fabric, e Perché È Necessaria? <a class="header-anchor" href="#cosa-fornisce-l-api-di-fabric-e-perche-e-necessaria" aria-label="Permalink to “Cosa Fornisce l&#39;API di Fabric, e Perché È Necessaria?”">​</a></h2><blockquote><p>L&#39;API di Fabric è un insieme di API e di strumenti per sviluppatori di mod da usare quando si creano mod.</p></blockquote><p>L&#39;API di Fabric fornisce un largo insieme di API che espandono le funzionalità esistenti di Minecraft - per esempio, fornendo nuovi hook ed eventi che i modder possono usare, o fornendo nuove utilità e strumenti per rendere il modding più facile - come access widener transitivi e la possibilità di accedere a registry interne, come la registry di oggetti compostabili.</p><p>Anche se l&#39;API di Fabric offre funzionalità potenti, alcune operazioni, come la registrazione basilare di blocchi, possono essere effettuate senza di essa usando le API vanilla.</p>`,22)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};